actions.script:
import org.moqui.util.RestClient

// requestItemList and bulkRequestItemList intentionally not used —
// the gateway re-queries the DB for all fieldbus configuration.

// resolve gateway base URL and optional API key
String rawUri = request.brokerUri
if (!rawUri) {
    ec.message.addError("DeviceRequest ${request.requestName} (deviceId=${request.deviceId}) " +
        "is missing brokerUri. Set brokerUri to the gateway REST base URL " +
        "(e.g. http://gateway-host:8081 or http://gateway-host:8081?apiKey=secret).")
    return
}

String gatewayBaseUrl = rawUri
String apiKey = null
int qIdx = rawUri.indexOf('?')
if (qIdx >= 0) {
    gatewayBaseUrl = rawUri.substring(0, qIdx)
    rawUri.substring(qIdx + 1).split('&').each { String kv ->
        String[] parts = kv.split('=', 2)
        if (parts.length == 2 && 'apiKey' == parts[0].trim()) apiKey = parts[1].trim()
    }
}
gatewayBaseUrl = gatewayBaseUrl.replaceAll('/+$', '')

// resolve gateway-side requestName from DeviceRequest.query
String gwRequestName = request.query
if (!gwRequestName) {
    ec.message.addError("DeviceRequest ${request.requestName} (deviceId=${request.deviceId}) " +
        "is missing query. Set query to the gateway-side requestName " +
        "(the DeviceRequest the gateway will look up in the shared DB).")
    return
}

// map requestTypeEnumId to gateway REST endpoint
String reqType = request.requestTypeEnumId
String path
if (reqType in ['DrtWrite', 'DrtConfigWrite', 'DrtRead']) {
    path = "/api/device-request/run/${gwRequestName}"
} else if (reqType in ['DrtSubscribe', 'DrtEvent', 'DrtStateChange', 'DrtCyclic']) {
    path = "/api/device-request/subscribe/${gwRequestName}"
} else if ('DrtUnsubscribe' == reqType) {
    path = "/api/device-request/unsubscribe/${gwRequestName}"
} else {
    ec.message.addError("Unsupported request type ${reqType} for gateway dispatch " +
        "(DeviceRequest ${request.requestName}, gateway requestName ${gwRequestName}).")
    return
}

// protocol detection (for logging only)
boolean isOpcUa = ('DcdOpcUa' == connection?.driverEnumId)
ec.logger.info("Dispatching ${reqType} to gateway ${gatewayBaseUrl}${path} " +
    "[protocol=${isOpcUa ? 'OPC UA' : 'MQTT'}, gwRequest=${gwRequestName}]")

// call gateway
int timeoutSec = request.timeout != null ? (int) request.timeout : 30
RestClient rc = new RestClient()
    .method(RestClient.POST)
    .uri(gatewayBaseUrl + path)
    .contentType("application/json")
    .acceptContentType("application/json")
    .timeout(timeoutSec)
if (apiKey) rc.addHeader("X-API-Key", apiKey)

RestClient.RestResponse resp = rc.call()
resp.checkError()

ec.logger.info("Gateway dispatch completed for ${gwRequestName}: ${resp.text()}")

import org.moqui.util.RestClient

// load DeviceContent
def content = ec.entity.find("moqui.device.DeviceContent")
    .condition("deviceContentId", deviceContentId).one()
if (!content) {
    ec.message.addError("DeviceContent ${deviceContentId} not found.")
    return
}
if (!content.contentLocation) {
    ec.message.addError("DeviceContent ${deviceContentId} has no contentLocation.")
    return
}

// load Moqui-side DeviceRequest
def dr = ec.entity.find("moqui.device.DeviceRequest")
    .condition("requestName", requestName).one()
if (!dr) {
    ec.message.addError("DeviceRequest ${requestName} not found.")
    return
}

// parse gateway base URL and optional API key from brokerUri
String rawUri = dr.brokerUri
if (!rawUri) {
    ec.message.addError("DeviceRequest ${requestName} is missing brokerUri (gateway REST base URL).")
    return
}
String gatewayBaseUrl = rawUri
String apiKey = null
int qIdx = rawUri.indexOf('?')
if (qIdx >= 0) {
    gatewayBaseUrl = rawUri.substring(0, qIdx)
    rawUri.substring(qIdx + 1).split('&').each { String kv ->
        String[] parts = kv.split('=', 2)
        if (parts.length == 2 && 'apiKey' == parts[0].trim()) apiKey = parts[1].trim()
    }
}
gatewayBaseUrl = gatewayBaseUrl.replaceAll('/+$', '')

String gwRequestName = dr.query
if (!gwRequestName) {
    ec.message.addError("DeviceRequest ${requestName} is missing query (gateway-side requestName).")
    return
}

// read file bytes via Moqui resource system and encode as Base64
InputStream is = ec.resource.getLocationReference(content.contentLocation).openStream()
byte[] fileBytes = is.bytes
is.close()
String encoded = java.util.Base64.encoder.encodeToString(fileBytes)
String filename = content.contentLocation.tokenize('/').last()

ec.logger.info("Transferring DeviceContent ${deviceContentId} (${filename}, ${fileBytes.length} bytes) " +
    "to gateway ${gatewayBaseUrl} → gwRequest=${gwRequestName}")

int timeoutSec = dr.timeout != null ? (int) dr.timeout : 30
RestClient rc = new RestClient()
    .method(RestClient.POST)
    .uri(gatewayBaseUrl + "/api/device-content/transfer/" + gwRequestName)
    .contentType("application/json")
    .acceptContentType("application/json")
    .timeout(timeoutSec)
if (apiKey) rc.addHeader("X-API-Key", apiKey)
rc.jsonObject([filename: filename, contentBase64: encoded, contentTypeEnumId: (content.contentTypeEnumId ?: '')])

RestClient.RestResponse resp = rc.call()
resp.checkError()

ec.logger.info("DeviceContent transfer completed: ${resp.text()}")
